    stats_.incRequestsRejectedWithUnderscoresInHeaders();
    return {HeaderEntryValidationResult::Action::Reject,
            UhvResponseCodeDetail::get().InvalidUnderscore};
  }

  return HeaderEntryValidationResult::success();
}

